	reason: string,
	artifacts: Awaited<ReturnType<typeof rebuildDocs>>,
): IndexerDiagnostic[] {
	const diagnostics: IndexerDiagnostic[] = [
		{
			severity: "warning",
			stage: "planning",
			message: reason,
		},
	];
	for (const rebuilt of artifacts.selectedDocs) {
		diagnostics.push(
			...rebuilt.compilerDiagnostics.map((diagnostic) => ({
